const Q_ECONOMICS_1990=[{"id": "objective>Economics>1990>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If one orange cost 20k and one kilogram of beef costs #10.00, the opportunity cost of one kilogram of beef is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50 orange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 orange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 orange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#9.80</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The opportunity cost of one kilogram of beef is the number of oranges that could be bought with the same amount of money. Since one kilogram of beef costs #10.00 and one orange costs 20k (which is #0.20) <br/>  <br/> we can calculate the opportunity cost as follows:  <br/> #10.00 / #0.20  <br/> = 50 oranges. </div>", "topic": "THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>1990>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In economic life, choice among alternative depends on the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Income of the decision make</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Scarcity of resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Scale of preference of the decision maker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Status of the decision maker</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economic life, choices among alternatives depend on the scarcity of resources. Scarcity means that resources are limited while human wants are unlimited, leading to the need for making choices. Therefore, the correct option is 'Scarcity of resources'.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>1990>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> A simple circular flow of income diagram <br/>  <br/> The flow labelled Y refers to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Real income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Factor payments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Factors input</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National income</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Flow Y goes from Firms to Households. It's in the money flow, not the real flow.. It represents the payments made to households for providing land, labor, capital, and enterprise. <br/>  <br/> These payments are: <br/> Rent for land <br/> Wages for labor <br/> Interest for capital <br/> Profit for enterprise <br/>  <br/> All of these together are called Factor Payments</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : INTRODUCTION"}, {"id": "objective>Economics>1990>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> A simple circular flow of income diagram <br/> The lower half of the diagram indicates </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The flow of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Payment for goods and  services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The flow income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Government transaction</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The lower half of the circular flow of income diagram represents the monetary flow from households to firms. It shows how households use their income to purchase goods and services produced by firms, completing the economic cycle. This spending is crucial as it generates revenue for firms and sustains economic activity.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : INTRODUCTION"}, {"id": "objective>Economics>1990>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major advantage of specialization is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The worker becomes a tender of machines</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It causes more employment of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Less machinery is required for production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The worker waste less time between operation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major advantages of specialization is that it allows workers to waste less time between operations, as they become more skilled and efficient in their specific tasks. This leads to increased productivity. Therefore, the correct option is 'The worker waste less time between operation'.</div>", "topic": "THEORY OF PRODUCTION : DIVISION OF LABOUR AND SPECIALISATION"}, {"id": "objective>Economics>1990>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following reward is associated with entrepreneurship as a factor of production?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Salaries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Profits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Interests</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rent</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reward associated with entrepreneurship as a factor of production is 'Profits'. Entrepreneurs take on the risk of starting and managing a business, and in return, they earn profits from their successful ventures. This is distinct from salaries, interests, and rent, which are associated with other factors of production.</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : WAGES"}, {"id": "objective>Economics>1990>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A firm achieves least-cost in production by substituting factors until</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Their prices are equal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The ratio of their marginal physical products equals the ratio of their prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Their marginal physical products are each equal to their factor prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Their marginal physical products are each equal to zero</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A firm achieves least-cost production by substituting factors until 'the ratio of their marginal physical products equals the ratio of their prices'. This is known as the equimarginal principle, which states that resources should be allocated in such a way that the last unit of money spent on each factor of production yields the same marginal product.</div>", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>1990>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economics of scale operate only when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Marginal cost is falling with input</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Average cost is falling with output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fixed cost is variable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Variable cost is less than fixed cost</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economies of scale operate when 'average cost is falling with output'. This occurs when increasing production leads to a lower cost per unit, often due to factors such as operational efficiencies and bulk purchasing of materials.</div>", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION"}, {"id": "objective>Economics>1990>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At the point of profit maximization by a firm, marginal costs is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Minimum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Falling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rising</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At the point of profit maximization by a firm, marginal costs are 'Constant'. This is because, at this point, the firm is producing the quantity of output where marginal cost equals marginal revenue, leading to maximum profit. If marginal costs were falling or rising, the firm could increase profits by adjusting output.</div>", "topic": "THEORY OF PRODUCTION : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>1990>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A situation in which all inputs are doubled and output also doubles is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Constant proportion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Constant returns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increasing returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Constant returns to scale</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A situation in which all inputs are doubled and output also doubles is known as 'Constant returns to scale'. This means that the production process is efficient, and the output increases in direct proportion to the increase in inputs.</div>", "topic": "THEORY OF PRODUCTION : LAWS OF PRODUCTION"}, {"id": "objective>Economics>1990>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The demand curve would shift to the right when there is a rise in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a rise in the price of a substitute goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the price of a substitute goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a fall in income of a consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price of the commodity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The demand curve shifts to the right when there is an increase in demand for a good. This can occur when there is a rise in the price of substitute goods. When the price of a substitute good increases, consumers are likely to buy more of the original good instead, leading to an increase in its demand. Therefore, the correct option is 'a rise in the price of a substitute goods'.</div>", "topic": "THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>1990>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The law of diminishing marginal utility indicates that if a consumer increase his consumption of a commodity continuously his</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Total utility must fall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marginal utility must fall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marginal utility may rise even though his total utility is falling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marginal utility may fall even though his total utility may be rising</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The law of diminishing marginal utility states that as a consumer increases the consumption of a commodity, the additional satisfaction (marginal utility) gained from consuming each additional unit decreases. Therefore, while total utility may continue to rise, the marginal utility derived from each additional unit consumed will fall.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND"}, {"id": "objective>Economics>1990>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Technical progress that leads to reduction in costs result in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">An increase in equilibrium price and quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in equilibrium price and quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An increase in equilibrium price and decrease in equilibrium quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in equilibrium price and increase in equilibrium quantity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Technical progress that leads to a reduction in costs typically results in an increase in supply. This increase in supply causes the equilibrium price to decrease and the equilibrium quantity to increase, as more of the product is available at lower prices.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>1990>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If an increase in income induces a reduction for the demand for beans, beans can be referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A normal good</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An inferior good</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A substitute</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A giffen good</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If an increase in income leads to a reduction in the demand for beans, this indicates that beans are an inferior good. Inferior goods are those for which demand decreases as consumer income rises, as consumers tend to purchase higher-quality substitutes when they have more income.</div>", "topic": "THEORY OF DEMAND : TYPES OF DEMAND"}, {"id": "objective>Economics>1990>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The demand for a product is said to be price inelastic if</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The price elasticity of demand is less than one</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The price elasticity of demand is greater than one</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A reduction in price results in an increase in quantity demanded</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An increase in price result in a decrease in the quantity demanded</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The demand for a product is said to be price inelastic if the price elasticity of demand is less than one. This means that the percentage change in quantity demanded is less than the percentage change in price, indicating that consumers are relatively unresponsive to price changes.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1990>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following graphs represents the price-quantity relationship between tea and lemon, if they are perfect complements?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When two commodities are perfect complementary, the shape of the curve is convex to the origin and it sloped downward from left to right indicating a negative slope.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>1990>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the below diagram, RTX, are the marginal cost and the average cost curve respectively of a perfectly competitive firm.  The supply curve of the firm is indicated by <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">TX</div>", "<div style=\"font-family:Cambria;font-size:17px;\">RT</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ST</div>", "<div style=\"font-family:Cambria;font-size:17px;\">TY</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The marginal cost curve of a firm is the supply curve. From point T to point X represents the supply curve of a firm.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>1990>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An imperfect market in which there is only one buyer of a commodity is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Monopsony</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oligopoly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monopoly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Duopoly</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An imperfect market with only one buyer is known as a 'Monopsony'. In a monopsony, the single buyer has significant control over the market, often leading to lower prices for the sellers. This is in contrast to a monopoly, where there is only one seller.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET - MONOPOLY"}, {"id": "objective>Economics>1990>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The tailoring service is competitive partly because it consists of a large number of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Large-scale enterprises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Medium scale enterprise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Small scale enterprises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Government -owned enterprises</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The tailoring service is competitive partly because it consists of a large number of 'Small scale enterprises'. These small businesses can adapt quickly to changes in consumer preferences and often provide personalized services, which enhances competition in the market.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>1990>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is applicable to a monopolistic firm operating at the output where marginal cost equals marginal revenue?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cost of production is at a minimum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The plants is of optimum size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Price is above marginal revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Average variable cost is at a minimum</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A monopolistic firm operating at the output where marginal cost equals marginal revenue when price is above the marginal revenue, but because they have market power, they can set their price above marginal cost unlike perfect competition.</div>", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION"}, {"id": "objective>Economics>1990>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the major function of the wholesaler?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bulk breaking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Provision of useful information to the manufacturer on products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Provision of after sales service to consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Provision of warehousing facility</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major function of the wholesaler is 'Bulk breaking'. Wholesalers purchase large quantities of goods from manufacturers and break them down into smaller quantities for resale to retailers or other businesses. This function helps in reducing the burden of inventory for manufacturers and provides convenience to retailers.</div>", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER"}, {"id": "objective>Economics>1990>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the distribution channels for goods and services, the middlemen's mark-up margin provides a rough measure for the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Quantity discount allowed of final consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reward for business entrepreneurship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Effectiveness of government control over economy's marketing channels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Extent of exploitation of the final consumer</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The middlemen's mark-up margin provides a rough measure for the 'Extent of exploitation of the final consumer'. This margin reflects the additional cost that consumers pay over the wholesale price, which can indicate how much value is added by the middlemen and how much they may be exploiting the consumer.</div>", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN"}, {"id": "objective>Economics>1990>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following reasons could induce a manufacturer to by pass te wholesaler in the distribution chain?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">To provide the quantity needed by retailers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To collect useful information on his products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To provide warehousing facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">To violate government regulation on distribution</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A manufacturer may choose to bypass the wholesaler to collect useful information on his products directly from retailers and consumers. This direct interaction can provide valuable insights into customer preferences and product performance, which can be crucial for improving product offerings and marketing strategies.</div>", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER"}, {"id": "objective>Economics>1990>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major difference between a state-owned enterprise and private enterprise is that the former</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Is not expected to cover its cost of production while the latter is</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Is not always expected to maximize profits while the latter is</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Has shareholders while the latte does not</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Has a board of directors while thelatter does not</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A state-owned enterprise is typically not always expected to maximize profits, as its primary goal may include social welfare and public service, unlike private enterprises which are primarily profit-driven. This distinction highlights the different objectives and operational frameworks of state-owned versus private enterprises.</div>", "topic": "BUSINESS ORGANISATION : PUBLIC CORPORATIONS"}, {"id": "objective>Economics>1990>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Divorce of ownership from control is a characteristics of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sole proprietorship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A limited liability company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Partnership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A private limite company</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Divorce of ownership from control is a characteristic of a limited liability company (LLC). In an LLC, the owners (members) are not necessarily involved in the day-to-day management of the company, which is typically handled by appointed managers. This separation allows for a distinct ownership structure where the financial liability of the owners is limited to their investment in the company.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>1990>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Capital provided by individuals to the firm by purchasing stocks is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Debt capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fixed capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Circulating</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equity capital</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capital provided by individuals to the firm by purchasing stocks is referred to as equity capital. This type of capital represents ownership in the company and comes with the expectation of returns through dividends and capital appreciation, distinguishing it from debt capital, which involves borrowing that must be repaid.</div>", "topic": "FINANCIAL INSTITUTION : STOCK EXCHANGE"}, {"id": "objective>Economics>1990>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors is the most important in siting a petro-chemical plant?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nearness to the source of raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nearness to the source of power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Availability of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Proximity of financial institutions</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important factor in siting a petro-chemical plant is near the source of raw materials. Proximity to raw materials reduces transportation costs and ensures a steady supply of inputs necessary for production, which is critical for the efficiency and profitability of the plant.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>1990>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will be the effect of allowing only economic factors to dictate the location of industries in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A more even development of the different parts of the country will be assured</div>", "<div style=\"font-family:Cambria;font-size:17px;\">There will be an unbalance spread in the distribution of industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The less developed parts of the country will be able to attract more industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Only the government will be able to finance the establishment of industries</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Allowing only economic factors to dictate the location of industries in Nigeria would likely lead to an unbalanced spread in the distribution of industries. This is because industries tend to cluster in areas with better infrastructure, resources, and market access, often neglecting less developed regions. Therefore, option B is correct.</div>", "topic": "ECONOMIC DEVELOPMENT : INTRODUCTION"}, {"id": "objective>Economics>1990>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the same basket of goods which cost N12.00 in 1985 cost N15.00 in 1987, price index for 1987 is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">125</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Price index = Price index of current year/ Price index of previous year x  100 <br/>  <br/> = 15/12  x 100 <br/> = 125%</div>", "topic": "INFLATION & DEFLATION : EFFECT"}, {"id": "objective>Economics>1990>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is likely to be inflationary?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tax increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Budget surplus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wage increases</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wage increases can lead to inflation as they increase the purchasing power of consumers, which can drive demand for goods and services. If demand outstrips supply, prices will rise, leading to inflation. </div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>1990>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basic purpose of imposing legal reserve requirements on commercial banks is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Assure the profitability of commercial banks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Provide a device through which credit creation by banks can be controlled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Provide a proper ratio between earning and non-bank assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Provide the Central Bank with working capital</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The basic purpose of imposing legal reserve requirements on commercial banks is to control the amount of credit that banks can create. By requiring banks to hold a certain percentage of deposits as reserves, the central bank can influence the money supply and ensure financial stability. Thus, option B is correct.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>1990>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Find the total credit that the banking system can create if primary deposits is just #100.00 while the cash ratio is 20%</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#700.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#600.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#500.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#400.00</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The total credit that the banking system can create is determined by the formula: Total Credit = Primary Deposits / Cash Ratio.  <br/>  <br/> Here, the primary deposit is #100.00 and the cash ratio is 20% (or 0.2).  <br/>  <br/> Therefore, Total Credit = 100 / 0.2 <br/>  = #500.00. </div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>1990>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a liability of a commercial bank?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Deposits in the bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Loans made by the bank to individuals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Loans made by the bank to other banks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bonds purchased by the bank</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deposits in the bank are considered liabilities for a commercial bank because they represent money that the bank owes to its depositors. When customers deposit money, the bank is obligated to return that money upon request, making it a liability on the bank's balance sheet.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>1990>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A tax on a commodity whose supply is perfectly inelastic is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Shifted completely on the consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Completely borne by the supplier</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Divide in the ratio 60: 40 between the consumer and the supplier</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Divided half-and-half between the producer and the consumer</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A tax on a commodity whose supply is perfectly inelastic means that the quantity supplied does not change regardless of the price. Therefore, the entire tax burden is shifted to the consumer, as suppliers cannot reduce supply in response to the tax.</div>", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX"}, {"id": "objective>Economics>1990>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the figure to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The relationship between tax rate and income which is relevant to a progressive tax is shown by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Curves Z and Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Curve X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Curve Z</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Curve Y</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A progressive tax is a tax in which the tax rate increases as the taxable amount increases. From the diagram above, curve Y represent the progressive system of taxation.</div>", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX"}, {"id": "objective>Economics>1990>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the figure to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The relationship between tax rate and income which is relevant to a proportional tax is depicted by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Curves Z and Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Curve X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Curve Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Curve Z</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A proportional tax is a tax imposed so that the tax rate is fixed, with no change as the taxable base amount increases or decreases. Curve Z represent propotional tax.</div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>1990>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under a system of freely floating exchange rate, an increase in the international value of a country(s) currency will cause</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Its exports to rise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Its imports to rise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gold to flow into that country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Its currency to be surplus</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under a system of freely floating exchange rates, an increase in the international value of a country's currency makes its goods more expensive for foreign buyers, leading to a decrease in exports. Conversely, imports become cheaper, resulting in an increase in imports.</div>", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE"}, {"id": "objective>Economics>1990>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Balance of trade is the difference between</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Exports and imports of goods and service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Capital inflows and capital outflows</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Visible and invisible balance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Exports and imports of goods</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The balance of trade is defined as the difference between the value of a country's exports and the value of its imports of goods and services. Therefore, the correct answer is 'Exports and imports of goods and service'.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>1990>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is likely to reduce a surplus in the balance of payments of a country?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Devaluation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increased tariff on imports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Export promotion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Currency appreciation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Currency appreciation makes a country's goods more expensive for foreign buyers, which can lead to a decrease in exports and an increase in imports, thus reducing a surplus in the balance of payments. Therefore, the correct answer is 'Currency appreciation'.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>1990>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a tariff?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Limit on the amount of good which can be imported</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Interest rate on foreign loans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Government payment to domestic producers for exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tax on imported goods</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A tariff is a tax imposed on imported goods, which raises the price of those goods and can protect domestic industries. Therefore, the correct answer is 'Tax on imported goods'.</div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>1990>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Import duties will increases total expenditure on imports if the demand for imports is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Infinitely elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Derived</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the demand for imports is inelastic, it means that consumers will continue to buy similar quantities of imports even if the price increases due to import duties. This results in an increase in total expenditure on imports. Therefore, the correct answer is 'Inelastic'.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>1990>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is likely to hinder labour mobility in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Higher wages elsewhere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cultural similarities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Good accommodation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ignorance of job opportunities elsewhere</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ignorance of job opportunities elsewhere can significantly hinder labor mobility, as individuals may not be aware of better job prospects in different locations. Therefore, the correct answer is 'Ignorance of job opportunities elsewhere'.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR"}, {"id": "objective>Economics>1990>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If birth rate is constant and death rate declines, population</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Falls</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Expands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stabilizes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oscillates</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the birth rate remains constant while the death rate declines, the population will expand. This is because a lower death rate means that more individuals are surviving, leading to an increase in the overall population size.</div>", "topic": "POPULATION : INTRODUCTION"}, {"id": "objective>Economics>1990>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the government invests the sum of #1,000,000.00 and the marginal propensity to consume is 0.75, what is the change in income?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#1000000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#4000000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#6000000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#14000000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The change in income can be calculated using the formula:  <br/> Change in Income = Investment x (1 / (1 - MPC)), where MPC is the marginal propensity to consume.  <br/>  <br/> Here, the investment is #1000.00 and the MPC is 0.75. <br/>  Therefore, Change in Income = #1,000,000 x (1 / (1 - 0.75)) <br/>  = #1,000,000 x 4  <br/> = #4,000,000 <br/> </div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : INVESTMENT FUNCTION"}, {"id": "objective>Economics>1990>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The system of measurement of national income as the sum of all final demands is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Income approach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Expenditure approach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Output approach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Value-added approach</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The system of measurement of national income as the sum of all final demands is known as the Expenditure approach. This approach calculates national income by adding up all expenditures made in the economy, including consumption, investment, government spending, and net exports.</div>", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME"}, {"id": "objective>Economics>1990>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Disposable income is an income which </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Is available for consumption and savings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pensions receive from the government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Is payable to the disabled members of the community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Accrues to the environmental sanitation authorities for refuse disposal</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Disposable income is defined as the income that is available for consumption and savings after taxes have been deducted. It represents the amount of money that households can spend or save as they choose.</div>", "topic": "BASIC CONCEPTS OF ECONOMICS"}, {"id": "objective>Economics>1990>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In equilibrium, injections are equal to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Withdrawals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Surplus of imports over exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Government spending</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wages</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In equilibrium, injections (such as investment, government spending, and exports) are equal to withdrawals (such as savings, taxes, and imports). This balance ensures that the economy is stable, with no excess supply or demand.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : INTRODUCTION"}, {"id": "objective>Economics>1990>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Social overhead capital refers to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Balanced growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gross investment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The building of infrastructures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Capital formation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Social overhead capital refers to the essential infrastructure that supports economic activity, such as transportation systems, communication networks, and utilities. These infrastructures are crucial for facilitating production and services in an economy. Therefore, the correct option is 'The building of infrastructures'.</div>", "topic": "ECONOMIC DEVELOPMENT : INTRODUCTION"}, {"id": "objective>Economics>1990>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most common index used for measuring development is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The level of literacy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Per capita income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nutritional level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Population growth rate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Per capita income is the most common index used for measuring development as it provides an average income per person in a given area, reflecting the economic well-being of the population. It is widely used because it allows for comparisons between different countries or regions. Thus, the correct option is 'Per capita income'.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>1990>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture is central to Nigeria's economy development because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's comparative advantage lies mainly in agro-allied industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture is the highest employer of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture accounts for an insignificant domestic product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria earns limitless foreign exchange from agriculture</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture is central to Nigeria's economic development primarily because it is the highest employer of labor in the country. A significant portion of the Nigerian population relies on agriculture for their livelihoods, making it a critical sector for economic stability and growth. Therefore, the correct option is 'Agriculture is the highest employer of labour'.</div>", "topic": "AGRICULTURE IN WEST AFRICA : ROLES"}];
